#include <iostream>
#include <string>
#include <cstring> 
using namespace std;
int a[103][103];
int main(){
    int n,m;
    cin>>n>>m;
    string s;
    getline(cin,s);
    for(int i=1;i<=n;i++){
    	string c;
    	getline(cin,c);
		for(int j=1;j<=m;j++){
    		if(c[j-1]=='*')a[i][j]=-1;
    	}
    }
    int sum=0;
    for(int i=1;i<=n;i++)
    	for(int j=1;j<=m;j++)
    		if(a[i][j]!=-1){
    			sum=0;
    			if(a[i-1][j-1]==-1)sum++;
    			if(a[i-1][j]==-1)sum++;
    			if(a[i-1][j+1]==-1)sum++;
    			if(a[i][j-1]==-1)sum++;
    			if(a[i][j+1]==-1)sum++;
    			if(a[i+1][j-1]==-1)sum++;
    			if(a[i+1][j]==-1)sum++;
    			if(a[i+1][j+1]==-1)sum++;
    			a[i][j]=sum;
    		}
    for(int i=1;i<=n;i++){
    	for(int j=1;j<=m;j++){
    		if(a[i][j]==-1)cout<<"*";
    		else cout<<a[i][j];
    	}
    	cout<<endl;
    }
    return 0;
}
